import { createSlice } from '@reduxjs/toolkit';
import { existsSync, readFileSync, writeFile } from 'fs';
// import i18next from 'i18next';
import { getUserDataDir } from 'pc-nrfconnect-shared';

const initialState = {
    nicknames: [],
};

const settingsFilePath = `${getUserDataDir()}/siatech-ble-updater/nicknames.json`;

if (existsSync(settingsFilePath)) {
    initialState.nicknames = JSON.parse(
        readFileSync(settingsFilePath).toString()
    );
    console.log('Nicknames loaded successfully');
    console.log(initialState.nicknames);
}

const deviceNicknamesSlice = createSlice({
    name: 'device-nicknames',
    initialState,
    reducers: {
        setNickname(state, action) {
            const { address, nickname } = action.payload;
            state.nicknames = state.nicknames.filter(
                n => n.address !== address.toLowerCase()
            );
            if (nickname !== '') {
                state.nicknames.push({
                    address: address.toLowerCase(),
                    nickname,
                });
            }
        },
        saveNicknames(state) {
            writeFile(
                settingsFilePath,
                JSON.stringify(state.nicknames, null, 2),
                err => {
                    if (!err) {
                        console.log('Nicknames saved successfully');
                    }
                }
            );
        },
    },
});

// Extract the action creators object and the reducer
const { actions, reducer } = deviceNicknamesSlice;
// Extract and export each action creator by name
export const { setNickname, saveNicknames } = actions;

export const getNickname = address => state =>
    state.nicknames.find(n => n.address === address.toLowerCase())?.nickname;
export const getNicknames = state => state.nicknames;
// Export the reducer, either as a default or named export
export default reducer;
