/* eslint-disable react/forbid-prop-types */

'use strict';

import React from 'react';
import Button from 'react-bootstrap/Button';
import { connect } from 'react-redux';
import PropTypes from 'prop-types';
import { bindActionCreators } from 'redux';

import * as AdapterActions from '../actions/adapterActions';
import * as AdvertisingActions from '../actions/advertisingActions';
import * as BLEEventActions from '../actions/bleEventActions';
import * as DeviceDetailsActions from '../actions/deviceDetailsActions';
import * as DfuActions from '../actions/dfuActions';
import * as SecurityActions from '../actions/securityActions';
import {
    getNickname,
    saveNicknames,
    setNickname,
} from '../reducers/deviceNicknamesReducer';
import { ImmutableDevice } from '../utils/api';

const RssiBars = ({ rssi }) => {
    let bars = 0;
    if (rssi < -100) {
        bars = 1;
    } else if (rssi < -80) {
        bars = 2;
    } else if (rssi < -60) {
        bars = 3;
    } else if (rssi < -45) {
        bars = 4;
    } else {
        bars = 5;
    }
    const fill = Array(5)
        .fill(0)
        .map((v, i) => (i < bars ? 'black' : 'lightgray'));
    return (
        <svg viewBox="0 0 14 16" width="14" className="rssi-bars">
            <rect x="0" y="14" width="2" height="2" fill={fill[0]} />
            <rect x="3" y="13" width="2" height="3" fill={fill[1]} />
            <rect x="6" y="11" width="2" height="5" fill={fill[2]} />
            <rect x="9" y="8" width="2" height="8" fill={fill[3]} />
            <rect x="12" y="4" width="2" height="12" fill={fill[4]} />
        </svg>
    );
};

RssiBars.propTypes = {
    rssi: PropTypes.number.isRequired,
};

class DiscoveredDevice extends React.PureComponent {
    constructor(props) {
        super(props);

        this.currentAdvType = undefined;
        this.currentFlags = undefined;
        this.currentServices = undefined;

        const { device, deviceNicknames } = this.props;
        const nickname =
            getNickname(device.address)(deviceNicknames) ||
            device.name ||
            '<Unknown name>';
        this.state = {
            nickname,
        };

        this.toggleExpand = this.toggleExpand.bind(this);
        this.onButtonClick = this.onButtonClick.bind(this);
    }

    onButtonClick(e, keepPropagation = false) {
        const { device, onCancelConnect, onConnect, adapterIsConnecting } =
            this.props;

        if (!keepPropagation) {
            e.stopPropagation();
        }

        if (adapterIsConnecting) {
            onCancelConnect(device);
        } else {
            onConnect(device);
        }
    }

    toggleExpand() {
        const { device, onToggleExpanded } = this.props;
        onToggleExpanded(device.address);
    }

    render() {
        const {
            device,
            isConnecting,
            adapterIsConnecting,
            selectedAdapter,
            showDfuDialog,
            disconnectFromDevice,
            setDeviceNickname,
            saveDevicesNicknames,
        } = this.props;

        const { nickname } = this.state;
        if (nickname === '<Unknown name>' && device.name) {
            this.setState({ nickname: device.name });
        }

        const instanceId = `${device.address}.0`;

        if (device.isExpanded) {
            if (device.advType) {
                this.currentAdvType = device.advType;
            }

            if (device.flags && device.flags.size > 0) {
                this.currentFlags = device.flags;
            }

            if (device.services && device.services.size > 0) {
                this.currentServices = device.services;
            }
        }

        if (!device) {
            return (
                <div>
                    <h3 style={{ textAlign: 'center' }}>Local dongle</h3>
                </div>
            );
        }

        const connectedDevice =
            selectedAdapter.connectedDevices.get(instanceId);

        if (
            connectedDevice &&
            connectedDevice.connected &&
            this.dfuDialogRequest
        ) {
            this.dfuDialogRequest = false;
            showDfuDialog(connectedDevice);
        }

        const dfuButton = (
            <Button
                type="button"
                onClick={e => {
                    if (!device.connected) {
                        this.onButtonClick(e, true);
                        this.dfuDialogRequest = true;
                    } else {
                        showDfuDialog(connectedDevice);
                    }
                }}
                variant="success"
                size="sm"
            >
                <span>Send DFU zip</span>
                <i className="mdi mdi-upload" />
            </Button>
        );

        const deviceName = (
            <>
                <div className="nickname-container">
                    <input
                        type="text"
                        className="nickname"
                        value={nickname}
                        onChange={e =>
                            this.setState({ nickname: e.target.value })
                        }
                        onKeyPress={e => {
                            if (e.key === 'Enter') {
                                document.activeElement.blur();
                            }
                        }}
                        onBlur={e => {
                            console.log('Saving...');
                            setDeviceNickname({
                                address: device.address,
                                nickname,
                            });
                            saveDevicesNicknames();
                            if (!e.target.value) {
                                this.setState({
                                    nickname: device.name || '<Unknown name>',
                                });
                            }
                        }}
                    />
                </div>
            </>
        );

        return (
            <div className="discovered-comhand">
                {deviceName}
                <div
                    className="address-text"
                    onDoubleClick={() => {
                        navigator.clipboard
                            .writeText(device.address.toLowerCase())
                            .then();
                    }}
                >
                    {device.address.toUpperCase()}
                </div>
                <div>
                    <span>{`${device.rssi} dBm`}</span>
                    <RssiBars rssi={device.rssi} />
                </div>
                <div className="buttons-container">
                    <div className="buttons">
                        <Button
                            type="button"
                            onClick={this.onButtonClick}
                            disabled={
                                (!isConnecting && adapterIsConnecting) ||
                                device.connected
                            }
                            size="sm"
                        >
                            <span>{isConnecting ? 'Cancel' : 'Connect'}</span>
                            <i className="mdi mdi-link-variant" />
                        </Button>
                        {dfuButton}
                        {device.connected && (
                            <Button
                                type="button"
                                variant="danger"
                                size="sm"
                                onClick={() => {
                                    disconnectFromDevice(connectedDevice);
                                }}
                            >
                                Disconnect
                            </Button>
                        )}
                    </div>
                </div>
            </div>
        );
    }
}

function mapStateToProps(state) {
    const { adapter, deviceNicknames } = state.app;

    const { selectedAdapter } = adapter;

    if (!selectedAdapter) {
        return {};
    }

    return {
        selectedAdapter,
        adapterState: selectedAdapter.state,
        selectedComponent:
            selectedAdapter.deviceDetails &&
            selectedAdapter.deviceDetails.selectedComponent,
        connectedDevices: selectedAdapter.connectedDevices,
        deviceDetails: selectedAdapter.deviceDetails,
        autoConnUpdate: adapter.autoConnUpdate,
        security: selectedAdapter.security,
        deviceNicknames,
    };
}

function mapDispatchToProps(dispatch) {
    const retval = {
        ...bindActionCreators(DeviceDetailsActions, dispatch),
        ...bindActionCreators(AdvertisingActions, dispatch),
        ...bindActionCreators(AdapterActions, dispatch),
        ...bindActionCreators(BLEEventActions, dispatch),
        ...bindActionCreators(SecurityActions, dispatch),
        ...bindActionCreators(DfuActions, dispatch),
        setDeviceNickname: action => dispatch(setNickname(action)),
        saveDevicesNicknames: () => dispatch(saveNicknames()),
    };

    return retval;
}

export default connect(mapStateToProps, mapDispatchToProps)(DiscoveredDevice);

DiscoveredDevice.propTypes = {
    device: PropTypes.instanceOf(ImmutableDevice).isRequired,
    // If adapter is currently connecting to a device
    adapterIsConnecting: PropTypes.bool.isRequired,
    // If adapter is currently connecting to this device
    isConnecting: PropTypes.bool.isRequired,
    onConnect: PropTypes.func.isRequired,
    onCancelConnect: PropTypes.func.isRequired,
    onToggleExpanded: PropTypes.func.isRequired,
    selectedAdapter: PropTypes.object,
    showDfuDialog: PropTypes.func,
    disconnectFromDevice: PropTypes.func,
    deviceNicknames: PropTypes.object,
    setDeviceNickname: PropTypes.func,
    saveDevicesNicknames: PropTypes.func,
};

