import React, { useEffect } from 'react';
import { App, getUserDataDir } from 'pc-nrfconnect-shared';

import BLEEventDialog from './lib/containers/BLEEventDialog';
import DeviceSelector from './lib/containers/DeviceSelector';
import DiscoveredComhands from './lib/containers/DiscoveredComhands';
import reducers from './lib/reducers';
import {
    confirmUserUUIDsExist,
    populateUuids,
} from './lib/utils/uuid_definitions';

import './resources/css/styles.scss';
import './resources/css/discovered-comhands.scss';

export default () => {
    useEffect(() => {
        confirmUserUUIDsExist(getUserDataDir());
        populateUuids();
    }, []);

    return (
        <App
            appReducer={reducers}
            deviceSelect={<DeviceSelector />}
            sidePanel={null}
            panes={[{ name: 'Wireless update', Main: DiscoveredComhands }]}
            showLogByDefault={false}
            reportUsageData={false}
        >
            <BLEEventDialog />
        </App>
    );
};
